import{_ as e,E as t}from"./app.a050b316.js";const s={},a=t('<h1 id="system-intent-and-system-frame" tabindex="-1"><a class="header-anchor" href="#system-intent-and-system-frame" aria-hidden="true">#</a> System Intent and System Frame</h1><h2 id="slot-update" tabindex="-1"><a class="header-anchor" href="#slot-update" aria-hidden="true">#</a> Slot Update</h2><h3 id="motivation" tabindex="-1"><a class="header-anchor" href="#motivation" aria-hidden="true">#</a> Motivation</h3><p>People want to change slots value for many reasons. The most possibles are: they made a silly mistake, or their previous choices put them between two fires, or they simply changed their mind.</p><p>io.framely.core.SlotUpdate offers an experience allowing one to change a slot value by a few words instead of redo the whole conversation. For example, when user change his mind during food ordering:</p><div class="custom-container conversation"><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>What kind of dish do you want? We have: 1. Pork Belly, 2. Roast Seabass 3. Roast Duck</p></div><div class="custom-container user"><p class="custom-container-title">User</p><p>The first one</p></div><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>OK. What kind of drink do you want? We have: 1. Cabernet Sauvignon 2. Riesling</p></div><div class="custom-container user"><p class="custom-container-title">User</p><p>I&#39;m really in the mood for something fresh and fruity now, so Riesling please. And can I change the previous order to Roast Seabass?</p></div><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>Sure. Changed dish from Pork Belly to Roast Seabass.</p></div></div><h3 id="analysis" tabindex="-1"><a class="header-anchor" href="#analysis" aria-hidden="true">#</a> Analysis</h3><p>Request for io.framely.core.SlotUpdate can be seen as a special digression, so user can express their willingness at anytime.</p><p>Clearly, they have to tell bot they want to change from what to what else. This means they might mention a specific slot, some slot value that they have given (an old value), some other value they want to update to (a new value), and when the slot is a multi-valued one, exactly which piece of value (the index) they want to change. io.framely.core.SlotUpdate supports user giving any combination of the information upon, and one can easily customize their own expressions in io.framely.core.SlotUpdate&#39;s Expression.</p><p>User expressions could be not instructional enough. In this case, bot will ask them for the missing necessities. For example, when user doesn&#39;t point out what new value should be changed to, bot will ask him with annotations defined in the updating slot to be supportive.</p><div class="custom-container conversation"><div class="custom-container user"><p class="custom-container-title">User</p><p>I want to change the Roast Seabass</p></div><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>What do you want to changes to, for dish? We have: 1. Pork Belly, 2. Roast Seabass 3. Roast Duck</p></div><div class="custom-container user"><p class="custom-container-title">User</p><p>Pork Belly</p></div></div><p>The bold texts are Value Recommendation of dish.</p><p>User expressions could also contradict each other. io.framely.core.SlotUpdate will ask them to clear out the inconsistency. For example, when user falsely remembers what he has ordered:</p><div class="custom-container conversation"><div class="custom-container user"><p class="custom-container-title">User</p><p>I want to change the first dish from Roast Duck to Pork Belly</p></div><div class="custom-container bot"><p class="custom-container-title">Bot</p><p>You just said Roast Duck, but the first dish is Roast Seabass. Do you mean you want to change Roast Seabass to Pork Belly?</p></div></div>',14);function o(n,i){return a}var c=e(s,[["render",o],["__file","systemframe.html.vue"]]);export{c as default};
